/* ---------- utils ---------- */
function hashStr(s) { let h = 1779033703; for (let i = 0; i < s.length; i++) { h = Math.imul(h ^ s.charCodeAt(i), 3432918353); h = (h << 13) | (h >>> 19); } return h >>> 0; }
function mulberry32(a) { return function () { a |= 0; a = (a + 0x6D2B79F5) | 0; let t = Math.imul(a ^ (a >>> 15), 1 | a); t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t; return ((t ^ (t >>> 14)) >>> 0) / 4294967296; }; }
function dailyPick(pool, dateStr, n = 5) {
  const rng = mulberry32(hashStr("homeground-" + dateStr));
  const arr = [...pool];
  for (let i = arr.length - 1; i > 0; i--) { const j = Math.floor(rng() * (i + 1)); [arr[i], arr[j]] = [arr[j], arr[i]]; }
  return arr.slice(0, Math.min(n, arr.length));
}
function haversine(a, b) {
  const R = 6371, rad = (x) => (x * Math.PI) / 180;
  const dLat = rad(b.lat - a.lat), dLon = rad(b.lon - a.lon);
  const s = Math.sin(dLat / 2) ** 2 + Math.cos(rad(a.lat)) * Math.cos(rad(b.lat)) * Math.sin(dLon / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(s));
}
const scoreFor = (km) => (km <= 25 ? 1000 : Math.max(0, Math.round(1000 * Math.exp(-(km - 25) / 1800))));
const toLatLon = (x, y) => ({ lon: (x / W) * 360 - 180, lat: 90 - (y / H) * 180 });
const toXY = (lat, lon) => ({ x: ((lon + 180) / 360) * W, y: ((90 - lat) / 180) * H });
const fmtKm = (km) => (km < 1 ? "<1 km" : km < 100 ? km.toFixed(1) + " km" : Math.round(km).toLocaleString() + " km");

/* ---------- storage ---------- */
async function sGet(key, shared = false) { try { const r = await window.storage.get(key, shared); return r ? JSON.parse(r.value) : null; } catch { return null; } }
async function sSet(key, value, shared = false) { try { return await window.storage.set(key, JSON.stringify(value), shared); } catch { return null; } }

/* ---------- map board ---------- */
function MapBoard({ pin, answer, revealed, onTap, height = 380 }) {
  const svgRef = useRef(null);
  const [view, setView] = useState({ x: 0, y: 0, w: W, h: H });
  const drag = useRef(null);

  const clientToSvg = useCallback((cx, cy) => {
    const rect = svgRef.current.getBoundingClientRect();
    return { x: view.x + ((cx - rect.left) / rect.width) * view.w, y: view.y + ((cy - rect.top) / rect.height) * view.h };
  }, [view]);

  const clampView = (v) => {
    const w = Math.min(Math.max(v.w, 60), W), h = w / 2;
    return { w, h, x: Math.min(Math.max(v.x, -w * 0.1), W - w * 0.9), y: Math.min(Math.max(v.y, -h * 0.1), H - h * 0.9) };
  };
  const zoomAt = (factor, cx, cy) => {
    setView((v) => {
      const px = cx ?? v.x + v.w / 2, py = cy ?? v.y + v.h / 2;
      const w = v.w * factor;
      return clampView({ w, h: w / 2, x: px - (px - v.x) * factor, y: py - (py - v.y) * factor });
    });
  };

  useEffect(() => {
    if (revealed && pin && answer) {
      const p1 = toXY(pin.lat, pin.lon), p2 = toXY(answer.lat, answer.lon);
      const minX = Math.min(p1.x, p2.x), maxX = Math.max(p1.x, p2.x);
      const minY = Math.min(p1.y, p2.y), maxY = Math.max(p1.y, p2.y);
      let w = Math.max((maxX - minX) * 1.9, (maxY - minY) * 3.8, 130);
      w = Math.min(w, W);
      const h = w / 2;
      setView({ x: Math.min(Math.max((minX + maxX) / 2 - w / 2, 0), W - w), y: Math.min(Math.max((minY + maxY) / 2 - h / 2, 0), H - h), w, h });
    }
  }, [revealed]);

  useEffect(() => { if (!revealed) setView({ x: 0, y: 0, w: W, h: H }); }, [revealed]);

  const onPointerDown = (e) => {
    e.currentTarget.setPointerCapture(e.pointerId);
    drag.current = { sx: e.clientX, sy: e.clientY, moved: 0, view: { ...view } };
  };
  const onPointerMove = (e) => {
    if (!drag.current) return;
    const dx = e.clientX - drag.current.sx, dy = e.clientY - drag.current.sy;
    drag.current.moved = Math.max(drag.current.moved, Math.hypot(dx, dy));
    const rect = svgRef.current.getBoundingClientRect();
    setView(clampView({ ...drag.current.view, x: drag.current.view.x - (dx / rect.width) * drag.current.view.w, y: drag.current.view.y - (dy / rect.height) * drag.current.view.h }));
  };
  const onPointerUp = (e) => {
    const d = drag.current; drag.current = null;
    if (d && d.moved < 6 && onTap && !revealed) {
      const p = clientToSvg(e.clientX, e.clientY);
      if (p.x >= 0 && p.x <= W && p.y >= 0 && p.y <= H) onTap(toLatLon(p.x, p.y));
    }
  };

  const mk = view.w / W; // marker scale so pins stay constant on screen
  const pinXY = pin ? toXY(pin.lat, pin.lon) : null;
  const ansXY = answer ? toXY(answer.lat, answer.lon) : null;

  return (
    <div style={{ position: "relative", borderRadius: 10, overflow: "hidden", border: `1px solid ${C.line}`, background: C.pitch }}>
      <svg
        ref={svgRef}
        viewBox={`${view.x} ${view.y} ${view.w} ${view.h}`}
        style={{ display: "block", width: "100%", height, touchAction: "none", cursor: revealed ? "grab" : "crosshair" }}
        onPointerDown={onPointerDown} onPointerMove={onPointerMove} onPointerUp={onPointerUp}
        onDoubleClick={(e) => { const p = clientToSvg(e.clientX, e.clientY); zoomAt(0.55, p.x, p.y); }}
      >
        <rect x={-200} y={-200} width={W + 400} height={H + 400} fill={C.pitch} />
        {/* pitch halfway + centre circle, faint */}
        <line x1={W / 2} y1={0} x2={W / 2} y2={H} stroke={C.line} strokeWidth={1.2 * mk} opacity={0.6} />
        <circle cx={W / 2} cy={H / 2} r={70} fill="none" stroke={C.line} strokeWidth={1.2 * mk} opacity={0.6} />
        <path d={MAP_PATH} fill="#16301F" stroke={C.chalkDim} strokeWidth={0.7 * mk} strokeLinejoin="round" opacity={0.95} />
        {revealed && pinXY && ansXY && (
          <line x1={pinXY.x} y1={pinXY.y} x2={ansXY.x} y2={ansXY.y} stroke={C.chalk} strokeWidth={1.6 * mk} strokeDasharray={`${6 * mk} ${5 * mk}`} opacity={0.9} />
        )}
        {pinXY && (
          <g transform={`translate(${pinXY.x} ${pinXY.y})`} style={{ pointerEvents: "none" }}>
            <g transform={`scale(${mk})`}>
              <line x1={-7} y1={-7} x2={7} y2={7} stroke={C.pitch} strokeWidth={6} strokeLinecap="round" />
              <line x1={-7} y1={7} x2={7} y2={-7} stroke={C.pitch} strokeWidth={6} strokeLinecap="round" />
              <line x1={-7} y1={-7} x2={7} y2={7} stroke={revealed ? C.red : C.amber} strokeWidth={3} strokeLinecap="round" />
              <line x1={-7} y1={7} x2={7} y2={-7} stroke={revealed ? C.red : C.amber} strokeWidth={3} strokeLinecap="round" />
            </g>
          </g>
        )}
        {revealed && ansXY && (
          <g transform={`translate(${ansXY.x} ${ansXY.y})`} style={{ pointerEvents: "none" }}>
            <g transform={`scale(${mk})`}>
              <circle r={9} fill="none" stroke={C.green} strokeWidth={2.5} />
              <circle r={3} fill={C.green} />
            </g>
          </g>
        )}
      </svg>
      <div style={{ position: "absolute", right: 10, top: 10, display: "flex", flexDirection: "column", gap: 6 }}>
        {[["+", 0.6], ["−", 1 / 0.6]].map(([label, f]) => (
          <button key={label} onClick={() => zoomAt(f)} style={{
            width: 34, height: 34, borderRadius: 8, border: `1px solid ${C.line}`, background: "rgba(10,24,16,0.85)",
            color: C.chalk, fontSize: 18, cursor: "pointer", lineHeight: 1,
          }}>{label}</button>
        ))}
      </div>
      {!revealed && (
        <div style={{ position: "absolute", left: 10, bottom: 8, fontSize: 11, color: C.chalkDim, letterSpacing: "0.08em", textTransform: "uppercase", pointerEvents: "none" }}>
          tap to drop your mark · drag to pan · double-tap to zoom
        </div>
      )}
    </div>
  );
}

/* ---------- shared UI bits ---------- */
const display = { fontFamily: "'Haettenschweiler','Arial Narrow',Impact,'Franklin Gothic Medium',sans-serif", textTransform: "uppercase", letterSpacing: "0.04em" };
const mono = { fontFamily: "ui-monospace,SFMono-Regular,Menlo,Consolas,monospace", fontVariantNumeric: "tabular-nums" };

function Btn({ children, onClick, tone = "amber", disabled, style }) {
  const bg = tone === "amber" ? C.amber : tone === "ghost" ? "transparent" : C.panel;
  const col = tone === "amber" ? "#141400" : C.chalk;
  return (
    <button onClick={onClick} disabled={disabled} style={{
      ...display, fontSize: 16, padding: "10px 22px", borderRadius: 9, cursor: disabled ? "default" : "pointer",
      background: disabled ? C.line : bg, color: disabled ? C.chalkDim : col,
      border: tone === "ghost" ? `1px solid ${C.line}` : "1px solid transparent", ...style,
    }}>{children}</button>
  );
}

/* ---------- play ---------- */
function PlayView({ questions, onFinished, savedResult }) {
  const [qi, setQi] = useState(0);
  const [pin, setPin] = useState(null);
  const [revealed, setRevealed] = useState(false);
  const [results, setResults] = useState([]);
  const [done, setDone] = useState(!!savedResult);
  const finalResults = savedResult || results;

  if (!questions.length) return <div style={{ color: C.chalkDim, padding: 30, textAlign: "center" }}>No fixtures scheduled. Ask the admin to add questions.</div>;

  if (done) {
    const total = finalResults.reduce((s, r) => s + r.pts, 0);
    return (
      <div>
        <div style={{ textAlign: "center", margin: "18px 0 6px" }}>
          <div style={{ ...display, fontSize: 15, color: C.chalkDim }}>Full time · {todayKey()}</div>
          <div style={{ ...display, fontSize: 64, color: C.amber, lineHeight: 1 }}>{total.toLocaleString()}</div>
          <div style={{ ...display, fontSize: 14, color: C.chalkDim }}>of {finalResults.length * 1000} points</div>
        </div>
        <div style={{ display: "grid", gap: 8, margin: "16px 0" }}>
          {finalResults.map((r, i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 9, padding: "10px 14px" }}>
              <div style={{ ...display, color: C.chalkDim, fontSize: 15, width: 26 }}>Q{i + 1}</div>
              <div style={{ flex: 1, fontSize: 13.5, color: C.chalk }}>{r.detail}</div>
              <div style={{ ...mono, fontSize: 12, color: C.chalkDim, whiteSpace: "nowrap" }}>{fmtKm(r.km)}</div>
              <div style={{ ...display, fontSize: 18, color: r.pts >= 700 ? C.green : r.pts >= 250 ? C.amber : C.red, width: 52, textAlign: "right" }}>{r.pts}</div>
            </div>
          ))}
        </div>
        <div style={{ textAlign: "center", color: C.chalkDim, fontSize: 13 }}>New fixtures at midnight. Check the leaderboard to see where you placed.</div>
      </div>
    );
  }

  const q = questions[qi];
  const km = pin && revealed ? haversine(pin, q) : null;

  const lockIn = () => {
    const d = haversine(pin, q);
    setResults((r) => [...r, { detail: q.detail, km: d, pts: scoreFor(d) }]);
    setRevealed(true);
  };
  const next = () => {
    if (qi + 1 >= questions.length) { setDone(true); onFinished(results); }
    else { setQi(qi + 1); setPin(null); setRevealed(false); }
  };

  return (
    <div>
      <div style={{ background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 10, padding: "12px 16px", margin: "12px 0" }}>
        <div style={{ ...display, fontSize: 13, color: C.amber, marginBottom: 4 }}>Question {qi + 1} of {questions.length} · {q.sport} · {q.year}</div>
        <div style={{ fontSize: 15.5, color: C.chalk, lineHeight: 1.45 }}>{q.prompt}</div>
      </div>
      <MapBoard pin={pin} answer={revealed ? q : null} revealed={revealed} onTap={setPin} />
      <div style={{ display: "flex", alignItems: "center", gap: 14, marginTop: 12, minHeight: 48 }}>
        {!revealed ? (
          <>
            <Btn onClick={lockIn} disabled={!pin}>Lock it in</Btn>
            <div style={{ color: C.chalkDim, fontSize: 13 }}>{pin ? "Mark placed. Lock it in to see the ruling." : "Drop your mark on the map."}</div>
          </>
        ) : (
          <>
            <Btn onClick={next}>{qi + 1 >= questions.length ? "Full time" : "Next question"}</Btn>
            <div style={{ fontSize: 14 }}>
              <span style={{ color: C.chalk }}>{q.detail}</span>
              <span style={{ color: C.chalkDim }}> — you were </span>
              <span style={{ ...mono, color: C.chalk }}>{fmtKm(km)}</span>
              <span style={{ color: C.chalkDim }}> off · </span>
              <span style={{ ...display, fontSize: 18, color: scoreFor(km) >= 700 ? C.green : scoreFor(km) >= 250 ? C.amber : C.red }}>+{scoreFor(km)}</span>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

/* ---------- leaderboard ---------- */
function LeaderboardView({ refreshKey }) {
  const [rows, setRows] = useState(null);
  useEffect(() => { (async () => setRows((await sGet("lb:" + todayKey(), true)) || []))(); }, [refreshKey]);
  const sorted = (rows || []).slice().sort((a, b) => b.score - a.score).slice(0, 50);
  return (
    <div>
      <div style={{ ...display, fontSize: 22, color: C.chalk, margin: "16px 0 10px" }}>Today's table <span style={{ color: C.chalkDim, fontSize: 14 }}>· {todayKey()}</span></div>
      {rows === null ? <div style={{ color: C.chalkDim }}>Loading…</div> :
        sorted.length === 0 ? <div style={{ color: C.chalkDim, padding: "20px 0" }}>No scores posted yet today. Finish a round to open the table.</div> : (
          <div style={{ display: "grid", gap: 6 }}>
            {sorted.map((r, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, background: i === 0 ? "#1C2E14" : C.panel2, border: `1px solid ${i === 0 ? C.amber + "55" : C.line}`, borderRadius: 9, padding: "9px 14px" }}>
                <div style={{ ...display, width: 30, color: i < 3 ? C.amber : C.chalkDim, fontSize: 16 }}>{i + 1}</div>
                <div style={{ flex: 1, color: C.chalk, fontSize: 14.5 }}>{r.name}</div>
                <div style={{ ...display, fontSize: 19, color: C.chalk }}>{r.score.toLocaleString()}</div>
              </div>
            ))}
          </div>
        )}
      <div style={{ color: C.chalkDim, fontSize: 12, marginTop: 14 }}>The leaderboard is shared — names and scores posted here are visible to everyone playing this game.</div>
    </div>
  );
}

/* ---------- admin ---------- */
function AdminView({ questions, setQuestions }) {
  const [authed, setAuthed] = useState(false);
  const [code, setCode] = useState("");
  const [cfg, setCfg] = useState(null);
  const [err, setErr] = useState("");
  const [editing, setEditing] = useState(null); // question object or null
  const [saving, setSaving] = useState(false);
  const [newCode, setNewCode] = useState("");

  useEffect(() => { (async () => { const c = await sGet("admin:cfg", true); setCfg(c || { passcode: DEFAULT_PASSCODE }); })(); }, []);

  const input = { background: C.pitch, border: `1px solid ${C.line}`, color: C.chalk, borderRadius: 8, padding: "9px 12px", fontSize: 14, width: "100%", boxSizing: "border-box" };
  const label = { ...display, fontSize: 12, color: C.chalkDim, marginBottom: 4, display: "block" };

  if (!authed) {
    return (
      <div style={{ maxWidth: 380, margin: "40px auto" }}>
        <div style={{ ...display, fontSize: 22, color: C.chalk, marginBottom: 4 }}>Manager's office</div>
        <div style={{ color: C.chalkDim, fontSize: 13, marginBottom: 14 }}>Enter the passcode to edit fixtures. Default is <span style={mono}>coach123</span> until changed. This is a light gate, not real security — anyone using this artifact shares the same question bank.</div>
        <input style={input} type="password" placeholder="Passcode" value={code} onChange={(e) => setCode(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter") { if (cfg && code === cfg.passcode) { setAuthed(true); setErr(""); } else setErr("Wrong passcode."); } }} />
        <div style={{ display: "flex", gap: 10, alignItems: "center", marginTop: 10 }}>
          <Btn onClick={() => { if (cfg && code === cfg.passcode) { setAuthed(true); setErr(""); } else setErr("Wrong passcode."); }}>Open office</Btn>
          {err && <span style={{ color: C.red, fontSize: 13 }}>{err}</span>}
        </div>
      </div>
    );
  }

  const persist = async (list) => {
    setSaving(true);
    const ok = await sSet("questions:all", list, true);
    setSaving(false);
    if (!ok) { setErr("Save failed — storage unavailable. Try again."); return false; }
    setErr(""); setQuestions(list); return true;
  };

  if (editing) {
    const e = editing;
    const set = (k, v) => setEditing({ ...e, [k]: v });
    const valid = e.prompt.trim() && e.detail.trim() && isFinite(parseFloat(e.lat)) && isFinite(parseFloat(e.lon));
    return (
      <div style={{ margin: "16px 0" }}>
        <div style={{ ...display, fontSize: 20, color: C.chalk, marginBottom: 10 }}>{e.id ? "Edit fixture" : "New fixture"}</div>
        <div style={{ display: "grid", gap: 10 }}>
          <div><span style={label}>Question (the moment)</span>
            <textarea style={{ ...input, minHeight: 60, resize: "vertical" }} value={e.prompt} onChange={(ev) => set("prompt", ev.target.value)} placeholder="e.g. The Miracle on Ice: US amateurs stun the Soviet hockey team…" /></div>
          <div><span style={label}>Answer shown after guessing (venue, city, country)</span>
            <input style={input} value={e.detail} onChange={(ev) => set("detail", ev.target.value)} placeholder="e.g. Olympic Center, Lake Placid, New York, USA" /></div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
            <div><span style={label}>Sport</span><input style={input} value={e.sport} onChange={(ev) => set("sport", ev.target.value)} /></div>
            <div><span style={label}>Year</span><input style={input} value={e.year} onChange={(ev) => set("year", ev.target.value)} /></div>
          </div>
          <div>
            <span style={label}>Location — tap the map to set it {e.lat !== "" && <span style={{ ...mono, color: C.amber, textTransform: "none" }}>({parseFloat(e.lat).toFixed(3)}, {parseFloat(e.lon).toFixed(3)})</span>}</span>
            <MapBoard height={300} pin={isFinite(parseFloat(e.lat)) ? { lat: parseFloat(e.lat), lon: parseFloat(e.lon) } : null} onTap={(p) => setEditing({ ...e, lat: p.lat, lon: p.lon })} />
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
            <Btn disabled={!valid || saving} onClick={async () => {
              const item = { ...e, id: e.id || "q" + Date.now(), lat: parseFloat(e.lat), lon: parseFloat(e.lon), year: parseInt(e.year) || "" };
              const list = e.id ? questions.map((q) => (q.id === e.id ? item : q)) : [...questions, item];
              if (await persist(list)) setEditing(null);
            }}>{saving ? "Saving…" : "Save fixture"}</Btn>
            <Btn tone="ghost" onClick={() => setEditing(null)}>Cancel</Btn>
            {err && <span style={{ color: C.red, fontSize: 13 }}>{err}</span>}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ margin: "16px 0" }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
        <div style={{ ...display, fontSize: 20, color: C.chalk }}>Fixture list <span style={{ color: C.chalkDim, fontSize: 13 }}>· {questions.length} questions · 5 drawn daily</span></div>
        <Btn onClick={() => setEditing({ prompt: "", detail: "", sport: "", year: "", lat: "", lon: "" })}>Add fixture</Btn>
      </div>
      {err && <div style={{ color: C.red, fontSize: 13, marginBottom: 8 }}>{err}</div>}
      <div style={{ display: "grid", gap: 6 }}>
        {questions.map((q) => (
          <div key={q.id} style={{ display: "flex", gap: 12, alignItems: "center", background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 9, padding: "10px 14px" }}>
            <div style={{ flex: 1 }}>
              <div style={{ color: C.chalk, fontSize: 13.5 }}>{q.prompt}</div>
              <div style={{ color: C.chalkDim, fontSize: 12, marginTop: 2 }}>{q.detail} · {q.sport} {q.year} · <span style={mono}>{q.lat.toFixed(2)}, {q.lon.toFixed(2)}</span></div>
            </div>
            <button style={{ ...display, background: "none", border: "none", color: C.amber, cursor: "pointer", fontSize: 13 }} onClick={() => setEditing({ ...q })}>Edit</button>
            <button style={{ ...display, background: "none", border: "none", color: C.red, cursor: "pointer", fontSize: 13 }} onClick={async () => { await persist(questions.filter((x) => x.id !== q.id)); }}>Delete</button>
          </div>
        ))}
      </div>
      <div style={{ marginTop: 24, borderTop: `1px solid ${C.line}`, paddingTop: 14, display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
        <span style={label}>Change passcode</span>
        <input style={{ ...input, width: 180 }} value={newCode} onChange={(e) => setNewCode(e.target.value)} placeholder="New passcode" />
        <Btn tone="ghost" onClick={async () => { if (newCode.trim()) { await sSet("admin:cfg", { passcode: newCode.trim() }, true); setCfg({ passcode: newCode.trim() }); setNewCode(""); } }}>Update</Btn>
        <span style={{ color: C.chalkDim, fontSize: 12 }}>Questions and passcode are stored in shared storage, visible to all players of this artifact.</span>
      </div>
    </div>
  );
}

/* ---------- name / submit modal ---------- */
function SubmitScore({ score, onDone }) {
  const [name, setName] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");
  useEffect(() => { (async () => { const me = await sGet("me"); if (me?.name) setName(me.name); })(); }, []);
  const submit = async () => {
    const n = name.trim().slice(0, 24) || "Anonymous";
    setBusy(true);
    const lbKey = "lb:" + todayKey();
    const rows = (await sGet(lbKey, true)) || [];
    const ok = await sSet(lbKey, [...rows, { name: n, score, ts: Date.now() }], true);
    await sSet("me", { name: n });
    setBusy(false);
    if (!ok) { setErr("Couldn't post the score — storage unavailable."); return; }
    onDone(true);
  };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(4,10,6,0.75)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 20 }}>
      <div style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 12, padding: 22, width: 340 }}>
        <div style={{ ...display, fontSize: 20, color: C.chalk }}>Post your score</div>
        <div style={{ ...display, fontSize: 40, color: C.amber, margin: "6px 0 10px" }}>{score.toLocaleString()}</div>
        <input autoFocus style={{ background: C.pitch, border: `1px solid ${C.line}`, color: C.chalk, borderRadius: 8, padding: "9px 12px", fontSize: 14, width: "100%", boxSizing: "border-box" }}
          placeholder="Name for the leaderboard" value={name} maxLength={24} onChange={(e) => setName(e.target.value)} onKeyDown={(e) => e.key === "Enter" && submit()} />
        <div style={{ color: C.chalkDim, fontSize: 11.5, margin: "8px 0" }}>Posted to a shared leaderboard everyone can see.</div>
        {err && <div style={{ color: C.red, fontSize: 13, marginBottom: 8 }}>{err}</div>}
        <div style={{ display: "flex", gap: 10 }}>
          <Btn onClick={submit} disabled={busy}>{busy ? "Posting…" : "Post score"}</Btn>
          <Btn tone="ghost" onClick={() => onDone(false)}>Skip</Btn>
        </div>
      </div>
    </div>
  );
}

/* ---------- app ---------- */
export default function App() {
  const [tab, setTab] = useState("play");
  const [questions, setQuestions] = useState(null);
  const [daily, setDaily] = useState([]);
  const [savedResult, setSavedResult] = useState(null);
  const [pendingScore, setPendingScore] = useState(null);
  const [lbRefresh, setLbRefresh] = useState(0);
  const [loadErr, setLoadErr] = useState("");

  useEffect(() => {
    (async () => {
      try {
        let qs = await sGet("questions:all", true);
        if (!qs || !qs.length) { qs = SEED_QUESTIONS; await sSet("questions:all", qs, true); }
        setQuestions(qs);
        setDaily(dailyPick(qs, todayKey()));
        setSavedResult(await sGet("played:" + todayKey()));
      } catch { setLoadErr("Couldn't load the question bank."); setQuestions(SEED_QUESTIONS); setDaily(dailyPick(SEED_QUESTIONS, todayKey())); }
    })();
  }, []);

  const onFinished = async (results) => {
    await sSet("played:" + todayKey(), results);
    setSavedResult(results);
    setPendingScore(results.reduce((s, r) => s + r.pts, 0));
  };

  const tabs = [["play", "Today's round"], ["board", "Leaderboard"], ["admin", "Admin"]];

  return (
    <div style={{ minHeight: "100vh", background: C.pitch, color: C.chalk, fontFamily: "system-ui,-apple-system,'Segoe UI',sans-serif", backgroundImage: `radial-gradient(ellipse 70% 45% at 50% -8%, rgba(255,211,92,0.10), transparent)` }}>
      <div style={{ maxWidth: 860, margin: "0 auto", padding: "18px 16px 50px" }}>
        <header style={{ display: "flex", alignItems: "baseline", gap: 14, flexWrap: "wrap", borderBottom: `1px solid ${C.line}`, paddingBottom: 12 }}>
          <div style={{ ...display, fontSize: 34, color: C.chalk, lineHeight: 1 }}>Home<span style={{ color: C.amber }}>Ground</span></div>
          <div style={{ fontSize: 12.5, color: C.chalkDim, letterSpacing: "0.06em", textTransform: "uppercase" }}>Tap where sports history happened · 5 questions a day</div>
          <nav style={{ marginLeft: "auto", display: "flex", gap: 6 }}>
            {tabs.map(([id, name]) => (
              <button key={id} onClick={() => { setTab(id); if (id === "board") setLbRefresh((x) => x + 1); }} style={{
                ...display, fontSize: 14, padding: "7px 14px", borderRadius: 8, cursor: "pointer",
                background: tab === id ? C.amber : "transparent", color: tab === id ? "#141400" : C.chalkDim,
                border: `1px solid ${tab === id ? C.amber : C.line}`,
              }}>{name}</button>
            ))}
          </nav>
        </header>
        {loadErr && <div style={{ color: C.red, fontSize: 13, marginTop: 10 }}>{loadErr} Playing from the built-in set.</div>}
        {questions === null ? <div style={{ color: C.chalkDim, padding: 40, textAlign: "center" }}>Warming up the floodlights…</div> : (
          <>
            {tab === "play" && <PlayView key={savedResult ? "done" : "live"} questions={daily} onFinished={onFinished} savedResult={savedResult} />}
            {tab === "board" && <LeaderboardView refreshKey={lbRefresh} />}
            {tab === "admin" && <AdminView questions={questions} setQuestions={(qs) => { setQuestions(qs); setDaily(dailyPick(qs, todayKey())); }} />}
          </>
        )}
        <footer style={{ marginTop: 34, color: C.chalkDim, fontSize: 11.5, borderTop: `1px solid ${C.line}`, paddingTop: 10 }}>
          Scoring: 1,000 points inside 25 km, decaying with distance. One round per day per player.
        </footer>
      </div>
      {pendingScore !== null && <SubmitScore score={pendingScore} onDone={() => { setPendingScore(null); setLbRefresh((x) => x + 1); }} />}
    </div>
  );
}
